public List<int[]> getRobotsPositions(int[][] inputMat, int[] directions) {
    int r = inputMat.length;
    int c = inputMat[0].length;
    List<int[]> out = new ArrayList<>();
    int[][][] distanceMat = new int[r][c][4];
    Queue<int[]> queue = new LinkedList<>();
    for (int i = 0; i < r; i++) {
      for (int j = 0; j < c; j++) {
        if (inputMat[i][j] == 2) {
          queue.add(new int[]{i, j});
        }
      }
    }
    int[][] dirs = {{0, -1}, {-1, 0}, {0, 1}, {1, 0}};
    while (!queue.isEmpty()) {
      int size = queue.size();
      while (size-- > 0) {
        int[] cell = queue.poll();
        for (int k = 0; k < dirs.length; k++) {
          int nr = cell[0] + dirs[k][0];
          int nc = cell[1] + dirs[k][1];
          if (nr >= 0 && nr < r && nc >= 0 && nc < c && inputMat[nr][nc] != 2 && distanceMat[nr][nc][k] == 0) {
            queue.add(new int[]{nr, nc});
            distanceMat[nr][nc][k] = distanceMat[cell[0]][cell[1]][k] + 1;
          }
        }
      }
    }
    for (int i = 0; i < r; i++) {
      for (int j = 0; j < c; j++) {
        if (inputMat[i][j] == 1) {
          int left = distanceMat[i][j][2];
          int top = distanceMat[i][j][3];
          int right = distanceMat[i][j][0];
          int bottom = distanceMat[i][j][1];
          if (left == directions[0]  && top == directions[1] && right == directions[2] && bottom == directions[3]) {
            out.add(new int[]{i, j});
          }
        }
      }
    }
    return out;
  }
